DROP TABLE IF EXISTS `products`;
CREATE TABLE `products` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_id` bigint unsigned NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `specs` json DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `products_slug_unique` (`slug`),
  KEY `products_category_id_foreign` (`category_id`),
  KEY `products_is_active_index` (`is_active`),
  CONSTRAINT `products_category_id_foreign` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `products` (`id`, `category_id`, `name`, `slug`, `description`, `specs`, `is_active`, `created_at`, `updated_at`, `deleted_at`) VALUES (1, 1, 'XETA F1 V2', 'xeta-f1-v2', 'Ultra-lightweight wireless gaming mouse with Hall Effect sensor. The F1 V2 features a 3950 DPI sensor, 55g weight, and 80-hour battery life.', '{\"dpi\": \"26000\", \"shape\": \"Symmetrical\", \"sensor\": \"PAW3950\", \"weight\": \"55g\", \"battery\": \"80 hours\", \"switches\": \"Hall Effect\", \"connectivity\": \"Wireless 2.4GHz / Bluetooth / USB-C\"}', 1, '2026-04-26 14:02:40', '2026-04-26 14:02:40', NULL),
(2, 1, 'XETA X1 V2', 'xeta-x1-v2', 'Ergonomic wireless gaming mouse with Rapid Trigger support. Features a 3395 sensor, 62g weight, and 100-hour battery.', '{\"dpi\": \"26000\", \"shape\": \"Ergonomic (Right-hand)\", \"sensor\": \"PAW3395\", \"weight\": \"62g\", \"battery\": \"100 hours\", \"switches\": \"Optical\", \"connectivity\": \"Wireless 2.4GHz / USB-C\"}', 1, '2026-04-26 14:02:40', '2026-04-26 14:02:40', NULL),
(3, 2, 'XETA K1 Pro', 'xeta-k1-pro', 'Full-size hot-swappable mechanical keyboard with Rapid Trigger support and Hall Effect magnetic switches. Gasket mounted, south-facing LEDs.', '{\"mount\": \"Gasket\", \"layout\": \"75%\", \"battery\": \"4000mAh\", \"keycaps\": \"PBT Double-shot\", \"switches\": \"Hall Effect Magnetic\", \"actuation\": \"0.1mm — 4.0mm adjustable\", \"connectivity\": \"USB-C / Wireless 2.4GHz / Bluetooth\", \"rapid_trigger\": true}', 1, '2026-04-26 14:02:40', '2026-04-26 14:02:40', NULL),
(4, 2, 'XETA K1 Mini', 'xeta-k1-mini', '60% compact keyboard with the same Hall Effect technology as the K1 Pro in a smaller form factor.', '{\"mount\": \"Gasket\", \"layout\": \"60%\", \"battery\": \"3000mAh\", \"keycaps\": \"PBT Double-shot\", \"switches\": \"Hall Effect Magnetic\", \"actuation\": \"0.1mm — 4.0mm adjustable\", \"connectivity\": \"USB-C / Wireless 2.4GHz\", \"rapid_trigger\": true}', 1, '2026-04-26 14:02:41', '2026-04-26 14:02:41', NULL),
(5, 3, 'XETA P1 Control', 'xeta-p1-control', 'Premium cloth mousepad optimized for control. Micro-textured surface provides consistent tracking with any sensor.', '{\"base\": \"Non-slip rubber\", \"edge\": \"Stitched\", \"sizes\": [\"M (360x300mm)\", \"L (490x420mm)\", \"XL (900x400mm)\"], \"surface\": \"Cloth — Control\", \"thickness\": \"4mm\"}', 1, '2026-04-26 14:02:41', '2026-04-26 14:02:41', NULL),
(6, 3, 'XETA P1 Speed', 'xeta-p1-speed', 'Glass-coated hybrid mousepad for maximum speed. Ultra-low friction surface for swift, precise movements.', '{\"base\": \"Non-slip rubber\", \"edge\": \"Rounded\", \"sizes\": [\"L (490x420mm)\", \"XL (900x400mm)\"], \"surface\": \"Glass-coated hybrid\", \"thickness\": \"3mm\"}', 1, '2026-04-26 14:02:41', '2026-04-26 14:02:41', NULL),
(7, 4, 'XETA Desk Mat', 'xeta-desk-mat', 'Large low-friction desk mat with stitched edges and a muted retail finish.', '{\"base\": \"Anti-slip rubber\", \"size\": \"900 x 400mm\", \"surface\": \"Speed cloth\"}', 1, '2026-04-26 14:02:41', '2026-04-26 14:03:35', NULL),
(8, 4, 'XETA Wrist Rest', 'xeta-wrist-rest', 'Minimal wrist support designed to sit flush under compact keyboards.', '{\"size\": \"75% / 60%\", \"cover\": \"Microfiber\", \"material\": \"Memory foam core\"}', 1, '2026-04-26 14:02:41', '2026-04-26 14:03:35', NULL),
(9, 4, 'XETA Coiled Cable', 'xeta-coiled-cable', 'Premium USB-C coiled cable to clean up the desk and frame the board.', '{\"finish\": \"Braided\", \"length\": \"1.8m\", \"connector\": \"USB-C\"}', 1, '2026-04-26 14:02:41', '2026-04-26 14:03:35', NULL);

DROP TABLE IF EXISTS `promotion_category`;
CREATE TABLE `promotion_category` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `promotion_id` bigint unsigned NOT NULL,
  `category_id` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `promotion_category_promotion_id_category_id_unique` (`promotion_id`,`category_id`),
  KEY `promotion_category_category_id_foreign` (`category_id`),
  CONSTRAINT `promotion_category_category_id_foreign` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE CASCADE,
  CONSTRAINT `promotion_category_promotion_id_foreign` FOREIGN KEY (`promotion_id`) REFERENCES `promotions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `promotion_product`;
CREATE TABLE `promotion_product` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `promotion_id` bigint unsigned NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `promotion_product_promotion_id_product_id_unique` (`promotion_id`,`product_id`),
  KEY `promotion_product_product_id_foreign` (`product_id`),
  CONSTRAINT `promotion_product_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `promotion_product_promotion_id_foreign` FOREIGN KEY (`promotion_id`) REFERENCES `promotions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `promotion_redemptions`;
CREATE TABLE `promotion_redemptions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `promotion_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `order_id` bigint unsigned DEFAULT NULL,
  `code_used` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `discount_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `metadata` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `promotion_redemptions_user_id_foreign` (`user_id`),
  KEY `promotion_redemptions_promotion_id_user_id_index` (`promotion_id`,`user_id`),
  KEY `promotion_redemptions_order_id_index` (`order_id`),
  CONSTRAINT `promotion_redemptions_order_id_foreign` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE SET NULL,
  CONSTRAINT `promotion_redemptions_promotion_id_foreign` FOREIGN KEY (`promotion_id`) REFERENCES `promotions` (`id`) ON DELETE CASCADE,
  CONSTRAINT `promotion_redemptions_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `promotions`;
CREATE TABLE `promotions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `discount_type` enum('percentage','fixed','bogo','bundle') COLLATE utf8mb4_unicode_ci NOT NULL,
  `scope` enum('order','product','category') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'order',
  `value` decimal(10,2) DEFAULT NULL,
  `buy_quantity` int unsigned DEFAULT NULL,
  `get_quantity` int unsigned DEFAULT NULL,
  `bundle_price` decimal(10,2) DEFAULT NULL,
  `min_purchase_amount` decimal(10,2) DEFAULT NULL,
  `first_order_only` tinyint(1) NOT NULL DEFAULT '0',
  `requires_code` tinyint(1) NOT NULL DEFAULT '0',
  `is_stackable` tinyint(1) NOT NULL DEFAULT '0',
  `priority` int unsigned NOT NULL DEFAULT '100',
  `starts_at` timestamp NULL DEFAULT NULL,
  `ends_at` timestamp NULL DEFAULT NULL,
  `usage_limit` int unsigned DEFAULT NULL,
  `usage_limit_per_user` int unsigned DEFAULT NULL,
  `usage_count` int unsigned NOT NULL DEFAULT '0',
  `conditions` json DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_by_user_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `promotions_code_unique` (`code`),
  KEY `promotions_created_by_user_id_foreign` (`created_by_user_id`),
  KEY `promotions_is_active_starts_at_ends_at_index` (`is_active`,`starts_at`,`ends_at`),
  KEY `promotions_scope_priority_index` (`scope`,`priority`),
  CONSTRAINT `promotions_created_by_user_id_foreign` FOREIGN KEY (`created_by_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `reviews`;
CREATE TABLE `reviews` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `variant_id` bigint unsigned DEFAULT NULL,
  `order_id` bigint unsigned NOT NULL,
  `rating` tinyint unsigned NOT NULL,
  `comment` text COLLATE utf8mb4_unicode_ci,
  `is_approved` tinyint(1) NOT NULL DEFAULT '0',
  `is_anonymous` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `reviews_user_id_variant_id_unique` (`user_id`,`variant_id`),
  KEY `reviews_product_id_foreign` (`product_id`),
  KEY `reviews_order_id_foreign` (`order_id`),
  KEY `reviews_variant_id_foreign` (`variant_id`),
  KEY `reviews_user_id_index` (`user_id`),
  CONSTRAINT `reviews_order_id_foreign` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE CASCADE,
  CONSTRAINT `reviews_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `reviews_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `reviews_variant_id_foreign` FOREIGN KEY (`variant_id`) REFERENCES `product_variants` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `sessions`;
CREATE TABLE `sessions` (
  `id` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_agent` text COLLATE utf8mb4_unicode_ci,
  `payload` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `last_activity` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `sessions_user_id_index` (`user_id`),
  KEY `sessions_last_activity_index` (`last_activity`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `support_messages`;
CREATE TABLE `support_messages` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `ticket_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `author_role` enum('customer','admin','system') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'customer',
  `message` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `support_messages_user_id_foreign` (`user_id`),
  KEY `support_messages_ticket_id_created_at_index` (`ticket_id`,`created_at`),
  CONSTRAINT `support_messages_ticket_id_foreign` FOREIGN KEY (`ticket_id`) REFERENCES `support_tickets` (`id`) ON DELETE CASCADE,
  CONSTRAINT `support_messages_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `support_tickets`;
CREATE TABLE `support_tickets` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned NOT NULL,
  `assigned_admin_id` bigint unsigned DEFAULT NULL,
  `ticket_number` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `subject` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` enum('order','payment','shipping','product','account','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'other',
  `status` enum('open','in_progress','waiting_customer','resolved','closed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'open',
  `channel` enum('web','email') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'web',
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `resolution_summary` text COLLATE utf8mb4_unicode_ci,
  `last_reply_at` timestamp NULL DEFAULT NULL,
  `resolved_at` timestamp NULL DEFAULT NULL,
  `closed_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `support_tickets_ticket_number_unique` (`ticket_number`),
  KEY `support_tickets_assigned_admin_id_foreign` (`assigned_admin_id`),
  KEY `support_tickets_user_id_created_at_index` (`user_id`,`created_at`),
  KEY `support_tickets_status_index` (`status`),
  CONSTRAINT `support_tickets_assigned_admin_id_foreign` FOREIGN KEY (`assigned_admin_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `support_tickets_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `clerk_id` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `first_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `last_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `username` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `address_line1` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `address_line2` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `city` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `state` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `postal_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `country` varchar(2) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `timezone` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `location_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `latitude` decimal(10,7) DEFAULT NULL,
  `longitude` decimal(10,7) DEFAULT NULL,
  `location_source` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `location_updated_at` timestamp NULL DEFAULT NULL,
  `role` enum('admin','customer') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'customer',
  `email_verified_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `users_email_unique` (`email`),
  UNIQUE KEY `users_clerk_id_unique` (`clerk_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

